const config = $('Config').first().json;
const url = config.qdrant_url + '/collections/' + config.collection;

let exists = false;
try {
  const resp = await this.helpers.httpRequest({ method: 'GET', url, json: true });
  exists = resp && resp.result && resp.result.status === 'green';
} catch (e) {
  exists = false;
}

if (!exists) {
  await this.helpers.httpRequest({
    method: 'PUT',
    url,
    body: { vectors: { size: 2048, distance: 'Cosine' } },
    json: true,
  });
}

return [{ json: { collection: config.collection, created: !exists } }];

const raw = $('Config').first().json.playlist_ids;
const entries = raw.split(',').map(s => s.trim()).filter(Boolean);
return entries.flatMap(entry => {
  const colonIdx = entry.indexOf(':');
  if (colonIdx === -1) return [{ json: { playlist_id: entry, playlist_name: entry } }];
  const candidateId = entry.slice(0, colonIdx).trim();
  const candidateName = entry.slice(colonIdx + 1).trim();
  if (!candidateId) return [];
  return [{ json: {
    playlist_id:   candidateId,
    playlist_name: candidateName || candidateId,
  }}];
});

const loopItem = $('Loop Playlists').first().json;
const playlistId = loopItem.playlist_id;
const playlistName = loopItem.playlist_name;
const config = $('Config').first().json;
const baseUrl = 'https://www.googleapis.com/youtube/v3/playlistItems';
const allVideos = [];
let pageToken = null;

do {
  let url = baseUrl
    + '?part=snippet'
    + '&playlistId=' + encodeURIComponent(playlistId)
    + '&maxResults=50'
    + '&key=' + encodeURIComponent(config.youtube_api_key);
  if (pageToken) url += '&pageToken=' + encodeURIComponent(pageToken);

  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url,
    json: true,
  });

  for (const item of (resp.items || [])) {
    const videoId = item.snippet && item.snippet.resourceId && item.snippet.resourceId.videoId;
    if (videoId) {
      allVideos.push({
        video_id:        videoId,
        playlist_id:     playlistId,
        published_at:    (item.snippet.publishedAt || null),
        collection:      config.collection,
        chunk_size:      config.chunk_size,
        embedding_model: config.embedding_model,
        playlist_name: playlistName,
      });
    }
  }

  pageToken = resp.nextPageToken || null;
} while (pageToken);

return allVideos.map(v => ({ json: v }));

const config = $('Config').first().json;
const video_id = $input.first().json.video_id;
const playlist_id = $input.first().json.playlist_id;

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: config.qdrant_url + '/collections/' + config.collection + '/points/scroll',
  body: {
    filter: { must: [
      { key: 'video_id', match: { value: video_id } },
      { key: 'playlist_id', match: { value: playlist_id } },
    ] },
    limit: 1,
    with_payload: false,
    with_vector: false,
  },
  json: true,
});

const exists = resp.result && resp.result.points && resp.result.points.length > 0;
return [{ json: { video_id, playlist_id, already_ingested: exists } }];

const transcript = $input.first().json;
const config = $('Config').first().json;
const loopData = $('Loop Videos').first().json;

if (!transcript.chunks || transcript.chunks.length === 0) {
  return [{ json: { status: 'skipped', video_id: transcript.video_id || 'unknown' } }];
}

function hashId(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h = Math.imul(h ^ str.charCodeAt(i), 16777619) >>> 0;
  }
  const hex = h.toString(16).padStart(8, '0').repeat(4).slice(0, 32);
  return `${hex.slice(0,8)}-${hex.slice(8,12)}-4${hex.slice(12,15)}-a${hex.slice(15,18)}-${hex.slice(18,30)}`;
}

async function embedBatch(texts) {
  for (let attempt = 0; attempt < 4; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: config.embedding_url + '/v1/embeddings',
        headers: { Authorization: 'Bearer ' + config.openrouter_api_key },
        body: { model: config.embedding_model, input: texts },
        json: true,
      });
      return resp.data.map(d => d.embedding);
    } catch (err) {
      if (attempt === 3) throw err;
      await new Promise(r => setTimeout(r, 2000 * Math.pow(2, attempt)));
    }
  }
}

const EMBED_BATCH = config.embed_batch_size || 50;
const chunks = transcript.chunks;
const allVectors = [];

for (let i = 0; i < chunks.length; i += EMBED_BATCH) {
  const batch = chunks.slice(i, i + EMBED_BATCH);
  const vectors = await embedBatch.call(this, batch.map(c => c.text));
  allVectors.push(...vectors);
  if (i + EMBED_BATCH < chunks.length) {
    await new Promise(r => setTimeout(r, 600));
  }
}

const points = chunks.map((chunk, idx) => ({
  id: hashId(`${loopData.playlist_id}_${transcript.video_id}_${chunk.chunk_id}`),
  vector: allVectors[idx],
  payload: {
    video_id:      transcript.video_id,
    playlist_id:   loopData.playlist_id || null,
    title:         transcript.title,
    channel:       transcript.channel,
    url:           transcript.url,
    published_at:  loopData.published_at || null,
    playlist_name: loopData.playlist_name || null,
    chunk_id:      chunk.chunk_id,
    start_time:    chunk.start_time ?? null,
    text:          chunk.text,
  },
}));

const QDRANT_BATCH = 100;
for (let i = 0; i < points.length; i += QDRANT_BATCH) {
  await this.helpers.httpRequest({
    method: 'PUT',
    url: config.qdrant_url + '/collections/' + config.collection + '/points',
    body: { points: points.slice(i, i + QDRANT_BATCH) },
    json: true,
  });
}

return [{ json: { status: 'ok', video_id: transcript.video_id, title: transcript.title, chunks_stored: chunks.length } }];

const config = $('Config').first().json;
const chatApiUrl = config.chat_api_url || 'http://chat-api:8000';
const collection = config.collection || 'podcasts';

const stats = await this.helpers.httpRequest({
  method: 'GET',
  url: `${chatApiUrl}/stats?collection=${collection}`,
  json: true,
});

return [{ json: stats }];
